	ida_struct.set_member_cmt(ida_struct.get_member(struc, 65960), '''String: "Sigurado ka bang gusto mong tanggalin ang key na ito\? Kung ito ay naibenta sa customer nang walang refund, ang iyong account ay mai-lock o made-disable."''', True)
	ida_struct.set_member_cmt(ida_struct.get_member(struc, 65952), '''String: "Adakah anda pasti mahu membuang kunci ini\? Jika ia telah dijual kepada pelanggan tanpa bayaran balik, akaun anda akan dikunci atau dilumpuhkan."''', True)
	ida_struct.set_member_cmt(ida_struct.get_member(struc, 65944), '''String: "क्या आप वाकई इस कुंजी को हटाना चाहते हैं\? यदि इसे बिना रिफंड के ग्राहक को बेचा गया था, तो आपका खाता लॉक या अक्षम हो जाएगा."''', True)
	ida_struct.set_member_cmt(ida_struct.get_member(struc, 65936), '''String: "¿Estás seguro de que quieres eliminar esta clave\? Si se vendió a un cliente sin reembolso, tu cuenta será bloqueada o deshabilitada."''', True)
	ida_struct.set_member_cmt(ida_struct.get_member(struc, 65928), '''String: "هل أنت متأكد من أنك تريد إزالة هذا المفتاح؟ إذا تم بيعه لعميل بدون استرداد، سيتم قفل أو تعطيل حسابك."''', True)
	ida_struct.set_member_cmt(ida_struct.get_member(struc, 65920), '''String: "Are you sure you want to remove this key\? If it was sold to a customer without a refund, your account will be locked or disabled."''', True)
	ida_struct.set_member_cmt(ida_struct.get_member(struc, 65912), '''String: "Babala, ang pag-lock ng key ay gagawing gumana lamang ito para sa device ID na ito (*) at hindi sa iba."''', True)
	ida_struct.set_member_cmt(ida_struct.get_member(struc, 65904), '''String: "Perhatian, Kunci yang dikunci hanya akan berfungsi untuk ID peranti ini (*) dan bukan yang lain."''', True)
	ida_struct.set_member_cmt(ida_struct.get_member(struc, 65896), '''String: "ध्यान दें, कुंजी को लॉक करने से यह केवल इस डिवाइस आईडी (*) के लिए काम करेगी और दूसरों के लिए नहीं."''', True)
	ida_struct.set_member_cmt(ida_struct.get_member(struc, 65888), '''String: "Atención, bloquear la clave hará que solo funcione para este ID de dispositivo (*) y no otros."''', True)
	ida_struct.set_member_cmt(ida_struct.get_member(struc, 65880), '''String: "تنبيه، قفل المفتاح سيجعله يعمل فقط على معرف الجهاز (*) وليس غيره."''', True)
	ida_struct.set_member_cmt(ida_struct.get_member(struc, 65872), '''String: "Attention, Lock the key will make it only work for this device id (*) and not others."''', True)
